 1	import * as React from "react";
 2	
 3	import { Button, GridItem, TextInput } from "@patternfly/react-core";
 4	import { MinusCircleIcon } from "@patternfly/react-icons";
 5	import { useNodeHealthCheckTranslation } from "localization/useNodeHealthCheckTranslation";
 6	
 7	export const AnnotationsModalRow: React.FC<{
 8	  annotation: { key: string; value: string };
 9	  onChange: ({ key, value }: { key: string; value: string }) => void;
10	  onDelete: () => void;
11	}> = React.memo(({ annotation, onChange, onDelete }) => {
12	  const { t } = useNodeHealthCheckTranslation();
13	  return (
14	    <>
15	      <GridItem span={5}>
16	        <TextInput
17	          autoFocus
18	          maxLength={255}
19	          className="nhc-annotation-form__input"
20	          size={1}
21	          placeholder={t("annotation key")}
22	          isRequired
23	          type="text"
24	          value={annotation.key}
25	          onChange={(_, newKey) => onChange({ ...annotation, key: newKey })}
26	          aria-label={t("annotation key")}
27	        />
28	      </GridItem>
29	      <GridItem span={5}>
30	        <TextInput
31	          maxLength={255}
32	          className="nhc-annotation-form__input"
33	          placeholder={t("annotation value")}
34	          isRequired
35	          type="text"
36	          value={annotation.value}
37	          onChange={(_, newValue) =>
38	            onChange({ ...annotation, value: newValue })
39	          }
40	          aria-label={t("annotation value")}
41	        />
42	      </GridItem>
43	      <GridItem span={2}>
44	        <Button onClick={() => onDelete()} variant="plain">
45	          <MinusCircleIcon />
46	        </Button>
47	      </GridItem>
48	    </>
49	  );
50	});
51	AnnotationsModalRow.displayName = "AnnotationModalRow";

